		DdxVersion:      s.DDxVersion,

package graphql_test

// Federation resolver integration tests (B14.6b). Exercises the four federated
// queries (federationNodes, federatedBeads, federatedRuns, federatedProjects)
// against two mock spoke servers. Verifies row shape, routing metadata, the
// partial-result rendering when one spoke is offline, and the version-skew
// rendering when one spoke is filtered by the handshake.

import (
	"context"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/DocumentDrivenDX/ddx/internal/federation"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// stubFederation is a minimal FederationProvider backed by a fixed list of
// spokes and a real (in-process) FanOutClient pointed at httptest spoke
// servers.
type stubFederation struct {
	spokes []federation.SpokeRecord
	client *federation.FanOutClient
}

func (s *stubFederation) Spokes() []federation.SpokeRecord {
	out := make([]federation.SpokeRecord, len(s.spokes))
	copy(out, s.spokes)
	return out
}

func (s *stubFederation) FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error) {
	return s.client.Execute(ctx, s.spokes, req)
}

func (s *stubFederation) ForwardMutation(ctx context.Context, req *federation.ForwardMutationRequest) (*federation.ForwardMutationResponse, error) {
	target := s.spoke(req.TargetNodeID)
	if target == nil {
		return nil, federation.ErrForwardMutationMissingOwner
	}
	resp, err := s.client.ForwardMutation(ctx, target, req.Body, req.Headers)
	if err != nil {
		return nil, err
	}
	defer func() { _ = resp.Body.Close() }()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}
	return &federation.ForwardMutationResponse{
		OriginIdentity:       req.OriginIdentity,
		ForwardingPath:       append([]string(nil), req.ForwardingPath...),
		RequestID:            req.RequestID,
		IdempotencyKey:       req.IdempotencyKey,
		TargetNodeID:         req.TargetNodeID,
		TargetProjectID:      req.TargetProjectID,
		ExpectedVersion:      req.ExpectedVersion,
		RequiredCapabilities: append([]string(nil), req.RequiredCapabilities...),
		StatusCode:           resp.StatusCode,
		Headers:              resp.Header.Clone(),
		Body:                 body,
	}, nil
}

func (s *stubFederation) spoke(nodeID string) *federation.SpokeRecord {
	for i := range s.spokes {
		if s.spokes[i].NodeID == nodeID {
			return &s.spokes[i]
		}
	}
	return nil
}

// newSpokeServer spins up an httptest server whose /graphql endpoint returns
// the canned JSON payload supplied by handler.
func newSpokeServer(t *testing.T, handlerFn func(req map[string]any) any) *httptest.Server {
	t.Helper()
	mux := http.NewServeMux()
	mux.HandleFunc("/graphql", func(w http.ResponseWriter, r *http.Request) {
		var body map[string]any
		_ = json.NewDecoder(r.Body).Decode(&body)
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(handlerFn(body))
	})
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	return srv
}

// newGQLHandlerWithFederation wires a minimal Resolver pointed at the supplied
// FederationProvider. The local query state provider is the same stub the
// other integration tests use, but no local data is exercised here.
func newGQLHandlerWithFederation(t *testing.T, fed ddxgraphql.FederationProvider) http.Handler {
	t.Helper()
	workDir, store := setupIntegrationDir(t)
	state := newTestStateProvider(workDir, store)
	gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers: &ddxgraphql.Resolver{
			State:      state,
			WorkingDir: workDir,
			Actions:    testActionDispatcher{},
			Federation: fed,
		},
		Directives: ddxgraphql.DirectiveRoot{},
	}))
	gqlSrv.AddTransport(transport.POST{})
	return gqlSrv
}

// TestFederation_QueryShape_TwoHealthySpokes exercises all four federated
// queries against two mock spokes, both healthy, and verifies that each
// returned row carries the routing metadata (nodeId, projectId, projectUrl,
// writeCapability, status) along with the typed payload shape.
func TestFederation_QueryShape_TwoHealthySpokes(t *testing.T) {
	skipIntegrationInShort(t)
	now := time.Date(2026, 5, 2, 12, 0, 0, 0, time.UTC)

	spoke1 := newSpokeServer(t, func(req map[string]any) any {
		// Same canned response for any query — body is asserted by the
		// resolver decode path, not by query string.
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-A1", "title": "spoke1 bead", "status": "open",
						"priority": 0, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p1",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-1", "layer": "run", "status": "success",
						"projectID": "p1", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p1", "name": "spoke1-proj", "path": "/tmp/p1",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})
	spoke2 := newSpokeServer(t, func(req map[string]any) any {
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-B1", "title": "spoke2 bead", "status": "open",
						"priority": 1, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p2",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-2", "layer": "run", "status": "running",
						"projectID": "p2", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p2", "name": "spoke2-proj", "path": "/tmp/p2",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})

	fed := &stubFederation{
		client: federation.NewFanOutClient(),
		spokes: []federation.SpokeRecord{
			{
				NodeID: "node-spoke1", Name: "spoke1", URL: spoke1.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "@identity:abc"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
			{
				NodeID: "node-spoke2", Name: "spoke2", URL: spoke2.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "write"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
		},
	}
	fed.client.HubDDxVersion = "0.1.0"
	fed.client.HubSchemaVersion = federation.CurrentSchemaVersion
	fed.client.PerNodeTimeout = 2 * time.Second

	h := newGQLHandlerWithFederation(t, fed)

	// federationNodes: surface should match spoke registry; @identity:* is
	// stripped; writeCapability flips per-spoke; lastHeartbeat is non-null
	// because the registry has a heartbeat timestamp.
	respNodes := gqlPost(t, h, `{ federationNodes {
		id nodeId name url status ddxVersion schemaVersion
		capabilities registeredAt lastHeartbeat writeCapability lastError
	} }`)
	var nodesData struct {
		FederationNodes []struct {
			ID              string   `json:"id"`
			NodeID          string   `json:"nodeId"`
			Name            string   `json:"name"`
			URL             string   `json:"url"`
			Status          string   `json:"status"`
			DdxVersion      string   `json:"ddxVersion"`
			SchemaVersion   string   `json:"schemaVersion"`
			Capabilities    []string `json:"capabilities"`
			RegisteredAt    string   `json:"registeredAt"`
			LastHeartbeat   *string  `json:"lastHeartbeat"`
			WriteCapability bool     `json:"writeCapability"`
			LastError       *string  `json:"lastError"`
		} `json:"federationNodes"`
	}
	if err := json.Unmarshal(respNodes["data"], &nodesData); err != nil {
		t.Fatalf("unmarshal nodes: %v", err)
	}
	if len(nodesData.FederationNodes) != 2 {
		t.Fatalf("want 2 federation nodes, got %d", len(nodesData.FederationNodes))
	}
	for _, n := range nodesData.FederationNodes {
		for _, c := range n.Capabilities {
			if len(c) > 0 && c[0] == '@' {
				t.Errorf("synthetic capability %q leaked through, expected filtered", c)
			}
		}
		if n.LastHeartbeat == nil {
			t.Errorf("node %s: expected non-null lastHeartbeat", n.NodeID)
		}
	}
	if got := nodesData.FederationNodes[0].WriteCapability; got != false {
		t.Errorf("spoke1 writeCapability: want false, got %v", got)
	}
	if got := nodesData.FederationNodes[1].WriteCapability; got != true {
		t.Errorf("spoke2 writeCapability: want true, got %v", got)
	}

	// federatedBeads: one row per spoke; each row carries projectUrl ==
	// spoke URL and the bead nested payload.
	respBeads := gqlPost(t, h, `{ federatedBeads {
		nodeId projectId projectUrl writeCapability status bead { id title status projectID }
	} }`)
	var beadsData struct {
		FederatedBeads []struct {
			NodeID          string  `json:"nodeId"`
			ProjectID       *string `json:"projectId"`
			ProjectURL      string  `json:"projectUrl"`

package federation

import (
	"fmt"
	"net/http"
	"strings"
)

// ForwardMutationRequest describes a hub-to-spoke owner-targeted mutation
// envelope. The request is deliberately narrow: it carries the origin and
// forwarding trail plus the single owning node/project pair that is allowed to
// execute the write.
type ForwardMutationRequest struct {
	OriginIdentity  string
	ForwardingPath  []string
	RequestID       string
	IdempotencyKey  string
	TargetNodeID    string
	TargetProjectID string
	ExpectedVersion *string

	// RequiredCapabilities lets the hub declare the minimum spoke capability
	// set needed for this mutation. The writer can reject requests that do not
	// advertise the required surface.
	RequiredCapabilities []string

	// Body and Headers carry the actual mutation envelope to the owning spoke.
	Body    []byte
	Headers map[string]string
}

// ForwardMutationResponse is the owning node's reply to a forwarded mutation
// request. It mirrors the request metadata so callers can correlate a result
// with the original write envelope.
type ForwardMutationResponse struct {
	OriginIdentity  string
	ForwardingPath  []string
	RequestID       string
	IdempotencyKey  string
	TargetNodeID    string
	TargetProjectID string
	ExpectedVersion *string

	RequiredCapabilities []string
	StatusCode           int
	Headers              http.Header
	Body                 []byte
}

// Validate checks the request for the narrow owner-targeted shape. The typed
// refusals are intentionally specific so callers can surface a stable reason.
func (r *ForwardMutationRequest) Validate() error {
	if r == nil {
		return ErrForwardMutationBroadcastLike
	}
	if strings.TrimSpace(r.TargetNodeID) == "" {
		return ErrForwardMutationMissingOwner
	}
	if strings.TrimSpace(r.TargetProjectID) == "" {
		return ErrForwardMutationMissingProject
	}
	if len(r.ForwardingPath) == 0 {
		return ErrForwardMutationBroadcastLike
	}
	return nil
}

// ForwardMutationRefusalKind is the stable refusal class surfaced by the
// federation forwarding contract.
type ForwardMutationRefusalKind string

const (
	ForwardMutationRefusalOffline        ForwardMutationRefusalKind = "offline"
	ForwardMutationRefusalStale          ForwardMutationRefusalKind = "stale"
	ForwardMutationRefusalReadOnly       ForwardMutationRefusalKind = "read_only"
	ForwardMutationRefusalMissingProject ForwardMutationRefusalKind = "missing-project"
	ForwardMutationRefusalMissingOwner   ForwardMutationRefusalKind = "missing-owner"
	ForwardMutationRefusalBroadcastLike  ForwardMutationRefusalKind = "broadcast-like"
)

func (k ForwardMutationRefusalKind) String() string { return string(k) }

// ForwardMutationRefusalError is a typed refusal that lets callers check a
// stable reason with errors.Is while still preserving a human-readable detail.
type ForwardMutationRefusalError struct {
	Kind   ForwardMutationRefusalKind
	Detail string
}

func (e *ForwardMutationRefusalError) Error() string {
	if e == nil {
		return "federation: forward mutation refused"
	}
	if e.Detail == "" {
		return fmt.Sprintf("federation: forward mutation refused: %s", e.Kind)
	}
	return fmt.Sprintf("federation: forward mutation refused: %s: %s", e.Kind, e.Detail)
}

// Is makes errors.Is match on refusal kind rather than pointer identity.
func (e *ForwardMutationRefusalError) Is(target error) bool {
	t, ok := target.(*ForwardMutationRefusalError)
	if !ok || e == nil || t == nil {
		return false
	}
	return e.Kind == t.Kind
}

var (
	ErrForwardMutationOffline        = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalOffline}
	ErrForwardMutationStale          = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalStale}
	ErrForwardMutationReadOnly       = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalReadOnly}
	ErrForwardMutationMissingProject = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalMissingProject}
	ErrForwardMutationMissingOwner   = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalMissingOwner}
	ErrForwardMutationBroadcastLike  = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalBroadcastLike}
)

	return out, nil
}

// federationNodeFromSpoke materializes one FederationNode row, filtering the
// synthetic identity capability and stamping a lastError diagnostic when
// supplied (e.g. for a version-skew handshake).
func federationNodeFromSpoke(s federation.SpokeRecord, lastError string) *FederationNode {
	caps := make([]string, 0, len(s.Capabilities))
	for _, c := range s.Capabilities {
		if strings.HasPrefix(c, federationIdentityPrefix) {
			continue
		}
		caps = append(caps, c)
	}
	n := &FederationNode{
		ID:              s.NodeID,
		NodeID:          s.NodeID,
		Name:            s.Name,
		URL:             s.URL,
		Status:          string(s.Status),
		DdxVersion:      s.DDxVersion,
		SchemaVersion:   s.SchemaVersion,
		Capabilities:    caps,
		RegisteredAt:    s.RegisteredAt.UTC().Format(time.RFC3339),
		WriteCapability: hasCapability(caps, federationCapWrite),
	}
	if !s.LastHeartbeat.IsZero() {
		ts := s.LastHeartbeat.UTC().Format(time.RFC3339)
		n.LastHeartbeat = &ts
	}
	if lastError != "" {
		le := lastError
		n.LastError = &le
	}
	return n
}

func hasCapability(caps []string, want string) bool {
	for _, c := range caps {
		if c == want {
			return true
		}
	}
	return false
}

func indexSpokes(spokes []federation.SpokeRecord) map[string]federation.SpokeRecord {
	out := make(map[string]federation.SpokeRecord, len(spokes))
	for _, s := range spokes {
		out[s.NodeID] = s
	}
	return out
}

package federation

import (
	"errors"
	"testing"
)

func TestFederationForwardMutationContract_CarriesTargetAndOriginMetadata(t *testing.T) {
	expectedVersion := "rev-42"
	req := &ForwardMutationRequest{
		OriginIdentity:       "localhost:127.0.0.1:55812",
		ForwardingPath:       []string{"hub-node", "spoke-node"},
		RequestID:            "req-123",
		IdempotencyKey:       "idem-456",
		TargetNodeID:         "spoke-node",
		TargetProjectID:      "project-789",
		ExpectedVersion:      &expectedVersion,
		RequiredCapabilities: []string{"write"},
		Body:                 []byte(`{"query":"mutation { __typename }"}`),
		Headers: map[string]string{
			"X-DDx-Origin-Identity": "localhost:127.0.0.1:55812",
		},
	}

	if req.OriginIdentity != "localhost:127.0.0.1:55812" {
		t.Fatalf("origin identity = %q, want %q", req.OriginIdentity, "localhost:127.0.0.1:55812")
	}
	if got := len(req.ForwardingPath); got != 2 || req.ForwardingPath[0] != "hub-node" || req.ForwardingPath[1] != "spoke-node" {
		t.Fatalf("forwarding path = %+v, want [hub-node spoke-node]", req.ForwardingPath)
	}
	if req.RequestID != "req-123" {
		t.Fatalf("request id = %q, want %q", req.RequestID, "req-123")
	}
	if req.IdempotencyKey != "idem-456" {
		t.Fatalf("idempotency key = %q, want %q", req.IdempotencyKey, "idem-456")
	}
	if req.TargetNodeID != "spoke-node" {
		t.Fatalf("target node id = %q, want %q", req.TargetNodeID, "spoke-node")
	}
	if req.TargetProjectID != "project-789" {
		t.Fatalf("target project id = %q, want %q", req.TargetProjectID, "project-789")
	}
	if req.ExpectedVersion == nil || *req.ExpectedVersion != expectedVersion {
		t.Fatalf("expected version = %+v, want %q", req.ExpectedVersion, expectedVersion)
	}
	if len(req.RequiredCapabilities) != 1 || req.RequiredCapabilities[0] != "write" {
		t.Fatalf("required capabilities = %+v, want [write]", req.RequiredCapabilities)
	}
}

func TestFederationForwardMutationContract_DefinesTypedRefusals(t *testing.T) {
	cases := []struct {
		name string
		err  error
		want ForwardMutationRefusalKind
	}{
		{name: "offline", err: ErrForwardMutationOffline, want: ForwardMutationRefusalOffline},
		{name: "stale", err: ErrForwardMutationStale, want: ForwardMutationRefusalStale},
		{name: "read_only", err: ErrForwardMutationReadOnly, want: ForwardMutationRefusalReadOnly},
		{name: "missing-project", err: ErrForwardMutationMissingProject, want: ForwardMutationRefusalMissingProject},
		{name: "missing-owner", err: ErrForwardMutationMissingOwner, want: ForwardMutationRefusalMissingOwner},
		{name: "broadcast-like", err: ErrForwardMutationBroadcastLike, want: ForwardMutationRefusalBroadcastLike},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if !errors.Is(&ForwardMutationRefusalError{Kind: tc.want}, tc.err) {
				t.Fatalf("errors.Is(kind=%q, %v) must be true", tc.want, tc.err)
			}
			var got *ForwardMutationRefusalError
			if !errors.As(tc.err, &got) {
				t.Fatalf("errors.As(%v) failed", tc.err)
			}
			if got.Kind != tc.want {
				t.Fatalf("refusal kind = %q, want %q", got.Kind, tc.want)
			}
			if got.Error() == "" {
				t.Fatalf("error string must not be empty")
			}
		})
	}

	if err := (&ForwardMutationRequest{TargetNodeID: "", TargetProjectID: "p", ForwardingPath: []string{"hub"}}).Validate(); !errors.Is(err, ErrForwardMutationMissingOwner) {
		t.Fatalf("Validate missing owner = %v, want missing-owner refusal", err)
	}
	if err := (&ForwardMutationRequest{TargetNodeID: "node", TargetProjectID: "", ForwardingPath: []string{"hub"}}).Validate(); !errors.Is(err, ErrForwardMutationMissingProject) {
		t.Fatalf("Validate missing project = %v, want missing-project refusal", err)
	}
	if err := (&ForwardMutationRequest{TargetNodeID: "node", TargetProjectID: "p"}).Validate(); !errors.Is(err, ErrForwardMutationBroadcastLike) {
		t.Fatalf("Validate missing forwarding path = %v, want broadcast-like refusal", err)
	}
}

package graphql

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// beadStore returns a bead.Store rooted at the per-request working directory
// (from ctx via WithWorkingDir, falling back to r.WorkingDir).
func (r *mutationResolver) beadStore(ctx context.Context) *bead.Store {
	return projectBeadStore(r.workingDir(ctx))
}

// beadModelFromBead converts a bead.Bead to the GraphQL Bead model.
func beadModelFromBead(b *bead.Bead) *Bead {
	gql := &Bead{
		ID:        b.ID,
		Title:     b.Title,
		Status:    b.Status,
		Priority:  b.Priority,
		IssueType: b.IssueType,
		CreatedAt: b.CreatedAt.UTC().Format(time.RFC3339),
		UpdatedAt: b.UpdatedAt.UTC().Format(time.RFC3339),
		Labels:    b.Labels,
	}
	if b.Owner != "" {
		gql.Owner = &b.Owner
	}
	if b.CreatedBy != "" {
		gql.CreatedBy = &b.CreatedBy
	}
	if b.Parent != "" {
		gql.Parent = &b.Parent
	}
	if b.Description != "" {
		gql.Description = &b.Description
	}
	if b.Acceptance != "" {
		gql.Acceptance = &b.Acceptance
	}
	if b.Notes != "" {
		gql.Notes = &b.Notes
	}
	for _, d := range b.Dependencies {
		dep := &Dependency{
			IssueID:     d.IssueID,
			DependsOnID: d.DependsOnID,
			Type:        d.Type,
		}
		if d.CreatedAt != "" {
			dep.CreatedAt = &d.CreatedAt
		}
		if d.CreatedBy != "" {
			dep.CreatedBy = &d.CreatedBy
		}
		if d.Metadata != "" {
			dep.Metadata = &d.Metadata
		}
		gql.Dependencies = append(gql.Dependencies, dep)
	}
	return gql
}

// BeadCreate is the resolver for the beadCreate mutation.
func (r *mutationResolver) BeadCreate(ctx context.Context, input BeadInput) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if input.Title == "" {
		return nil, fmt.Errorf("title is required")
	}

	b := &bead.Bead{
		Title: input.Title,
	}
	if input.Status != nil {
		b.Status = *input.Status
	}
	if input.Priority != nil {
		b.Priority = *input.Priority
	}
	if input.IssueType != nil {
		b.IssueType = *input.IssueType
	}
	if input.Labels != nil {
		b.Labels = input.Labels
	}
	if input.Parent != nil {
		b.Parent = *input.Parent
	}
	if input.Description != nil {
		b.Description = *input.Description
	}
	if input.Acceptance != nil {
		b.Acceptance = *input.Acceptance
	}
	if input.Notes != nil {
		b.Notes = *input.Notes
	}

	store := r.beadStore(ctx)
	if err := store.Create(ctx, b); err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUpdate is the resolver for the beadUpdate mutation.
func (r *mutationResolver) BeadUpdate(ctx context.Context, id string, input BeadUpdateInput) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	mutate := func(b *bead.Bead) error {
		if input.Title != nil {
			b.Title = *input.Title
		}
		if input.Priority != nil {
			b.Priority = *input.Priority
		}
		if input.IssueType != nil {
			b.IssueType = *input.IssueType
		}
		if input.Labels != nil {
			b.Labels = input.Labels
		}
		if input.Parent != nil {
			b.Parent = *input.Parent
		}
		if input.Description != nil {
			b.Description = *input.Description
		}
		if input.Acceptance != nil {
			b.Acceptance = *input.Acceptance
		}
		if input.Notes != nil {
			b.Notes = *input.Notes
		}
		return nil
	}
	var err error
	if input.Status != nil {
		err = store.UpdateWithLifecycleStatus(id, *input.Status, bead.LifecycleTransitionOptions{
			Reason: "graphql bead update",
			Source: "graphql:beadUpdate",
		}, mutate)
	} else {
		err = store.Update(ctx, id, func(b *bead.Bead) {
			_ = mutate(b)
		})
	}
	if err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadClaim is the resolver for the beadClaim mutation.
func (r *mutationResolver) BeadClaim(ctx context.Context, id string, assignee string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Claim(id, assignee); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUnclaim is the resolver for the beadUnclaim mutation.
func (r *mutationResolver) BeadUnclaim(ctx context.Context, id string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Unclaim(id); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadReopen is the resolver for the beadReopen mutation.
func (r *mutationResolver) BeadReopen(ctx context.Context, id string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Reopen(id, "graphql bead reopen", ""); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"strings"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID        string      `json:"node_id"`
	Name          string      `json:"name"`
	URL           string      `json:"url"`
	DDxVersion    string      `json:"ddx_version,omitempty"`
	SchemaVersion string      `json:"schema_version,omitempty"`
	Capabilities  []string    `json:"capabilities,omitempty"`
	ProjectIDs    []string    `json:"project_ids,omitempty"`
	RegisteredAt  time.Time   `json:"registered_at"`
	LastHeartbeat time.Time   `json:"last_heartbeat"`
	Status        SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

// RouteMutationToProjectOwner returns the spoke registered as owning projectID.
// A project may be owned by exactly one spoke. If no owner is registered, or if
// multiple spokes claim the same project, the helper returns an error.
func RouteMutationToProjectOwner(registry *FederationRegistry, projectID string) (*SpokeRecord, error) {
	if registry == nil {
		return nil, fmt.Errorf("federation: registry is nil")
	}
	projectID = strings.TrimSpace(projectID)
	if projectID == "" {
		return nil, fmt.Errorf("federation: project_id required")
	}

	var match *SpokeRecord
	for i := range registry.Spokes {
		spoke := &registry.Spokes[i]
		for _, owned := range spoke.ProjectIDs {
			if owned == projectID {
				if match != nil {
					return nil, fmt.Errorf("federation: project %q has multiple registered owners", projectID)
				}
				copy := *spoke
				match = &copy
				break
			}
		}
	}
	if match == nil {
		return nil, fmt.Errorf("federation: no registered spoke owns project %q", projectID)
	}
	return match, nil
}

package federation

import (
	"bytes"
	"context"
	"crypto/rand"
	"crypto/tls"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"math/big"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// DefaultHeartbeatInterval is the nominal heartbeat cadence (ADR-007: 30s).
const DefaultHeartbeatInterval = 30 * time.Second

// DefaultHeartbeatJitterFraction is applied to the interval as ±jitter so
// independent spokes do not synchronize their beats against one hub. On the
// default 30s cadence this yields a ±5s window, matching ADR-007.
const DefaultHeartbeatJitterFraction = 5.0 / 30.0

// DefaultDeregisterTimeout caps the best-effort deregister request on shutdown.
const DefaultDeregisterTimeout = 2 * time.Second

// spokeStateFileName is the on-disk name for spoke-side state, used to detect
// URL changes across restarts so the spoke can re-register with a new URL.
const spokeStateFileName = "spoke-state.json"

// SpokeState is the per-spoke persistent state. It records the URL last
// advertised to the hub and the stable identity_fingerprint generated on
// first start, both so URL changes can be detected across restarts and so
// re-registration can prove identity to the hub.
type SpokeState struct {
	NodeID              string `json:"node_id"`
	IdentityFingerprint string `json:"identity_fingerprint"`
	LastURL             string `json:"last_url,omitempty"`
}

// DefaultSpokeStatePath returns ~/.local/share/ddx/spoke-state.json (XDG aware).
func DefaultSpokeStatePath() (string, error) {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx", spokeStateFileName), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".local", "share", "ddx", spokeStateFileName), nil
}

// LoadSpokeState reads spoke state from path. Missing file → zero value.
func LoadSpokeState(path string) (*SpokeState, error) {
	data, err := os.ReadFile(path)
	if errors.Is(err, os.ErrNotExist) {
		return &SpokeState{}, nil
	}
	if err != nil {
		return nil, fmt.Errorf("federation: read spoke state: %w", err)
	}
	var st SpokeState
	if err := json.Unmarshal(data, &st); err != nil {
		// Corrupt file — start fresh; the caller will overwrite.
		return &SpokeState{}, nil
	}
	return &st, nil
}

// SaveSpokeState writes spoke state to path atomically (tmpfile+rename).
func SaveSpokeState(path string, st *SpokeState) error {
	if st == nil {
		return fmt.Errorf("federation: nil spoke state")
	}
	if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
		return fmt.Errorf("federation: mkdir: %w", err)
	}
	data, err := json.MarshalIndent(st, "", "  ")
	if err != nil {
		return err
	}
	tmp, err := os.CreateTemp(filepath.Dir(path), ".spoke-state-*.json.tmp")
	if err != nil {
		return err
	}
	tmpPath := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpPath)
		return err
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	if err := os.Chmod(tmpPath, fileMode); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	return os.Rename(tmpPath, path)
}

// generateIdentityFingerprint returns a random 16-byte hex string. The
// fingerprint is generated once per node and persisted in spoke-state so a
// re-registration of the same node_id from the same machine is recognized
// as such (rather than rejected as a duplicate-identity conflict).
func generateIdentityFingerprint() string {
	var buf [16]byte
	if _, err := rand.Read(buf[:]); err != nil {
		// Fall back to a hostname-derived value; collisions here are
		// uninteresting because the hub's duplicate-id rejection only fires
		// on a *different* fingerprint claiming the same node_id.
		host, _ := os.Hostname()
		return "fp-" + host
	}
	return "fp-" + hex.EncodeToString(buf[:])
}

// SpokeConfig configures a Spoke lifecycle agent. URL is the spoke's own
// publicly-reachable URL (advertised to the hub); HubURL is the hub base URL
// (e.g. "https://hub.example:7743").
type SpokeConfig struct {
	NodeID               string
	Name                 string
	URL                  string
	HubURL               string
	DDxVersion           string
	SchemaVersion        string
	GraphQLSchemaVersion string
	Capabilities         []string
	ProjectIDs           []string

	// HeartbeatInterval defaults to DefaultHeartbeatInterval. Pass a small
	// value (e.g. 50ms) in tests.
	HeartbeatInterval time.Duration
	// HeartbeatJitterFraction is the ± jitter as a fraction of the interval
	// (e.g. 0.25 for ±25%). Defaults to DefaultHeartbeatJitterFraction.
	HeartbeatJitterFraction float64
	// DeregisterTimeout caps the best-effort deregister on shutdown.
	DeregisterTimeout time.Duration

	// StatePath is the disk path for spoke-state.json. Empty → DefaultSpokeStatePath.
	StatePath string
	// HTTPClient is used for hub requests. Nil → default client that accepts
	// self-signed certs (matches the server's auto-generated cert).
	HTTPClient *http.Client
	// Logger is used for warn/info; nil → log.Printf.
	Logger func(format string, args ...any)
}

// Spoke is the spoke-side lifecycle agent: register on Start, jittered
// heartbeat in the background, deregister best-effort on Shutdown.
type Spoke struct {
	cfg                 SpokeConfig
	identityFingerprint string

	mu              sync.Mutex
	statePath       string
	registered      bool
	stopped         chan struct{}
	stopOnce        sync.Once
	registeredCount int // test introspection
	heartbeatCount  int // test introspection
	urlChanged      bool
	urlChangedFrom  string
	hbErr           error
	logf            func(format string, args ...any)
}

// NewSpoke constructs a Spoke with defaults filled in. The spoke is not
// started until Start is called.
func NewSpoke(cfg SpokeConfig) (*Spoke, error) {
	if strings.TrimSpace(cfg.NodeID) == "" {
		return nil, fmt.Errorf("federation: spoke NodeID required")
	}
	if strings.TrimSpace(cfg.HubURL) == "" {
		return nil, fmt.Errorf("federation: spoke HubURL required")
	}
	if strings.TrimSpace(cfg.URL) == "" {
		return nil, fmt.Errorf("federation: spoke URL required")
	}
	if cfg.HeartbeatInterval <= 0 {
		cfg.HeartbeatInterval = DefaultHeartbeatInterval
	}
	if cfg.HeartbeatJitterFraction < 0 {
		cfg.HeartbeatJitterFraction = 0
	}
	if cfg.HeartbeatJitterFraction == 0 {
		cfg.HeartbeatJitterFraction = DefaultHeartbeatJitterFraction
	}
	if cfg.DeregisterTimeout <= 0 {
		cfg.DeregisterTimeout = DefaultDeregisterTimeout
	}
	if cfg.HTTPClient == nil {
		// Self-signed certs are the default for ddx-server, so the spoke
		// must skip cert verification by default. Operators wanting stricter
		// validation can pass a custom HTTPClient.
		cfg.HTTPClient = &http.Client{
			Timeout: 10 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		}
	}

	statePath := cfg.StatePath
	if statePath == "" {
		p, err := DefaultSpokeStatePath()
		if err != nil {
			return nil, err
		}
		statePath = p
	}

	logf := cfg.Logger
	if logf == nil {
		logf = func(format string, args ...any) { log.Printf(format, args...) }
	}

	st, err := LoadSpokeState(statePath)
	if err != nil {
		return nil, err
	}

	// Detect URL change between restarts.
	var urlChanged bool
	var prevURL string
	if st.NodeID == cfg.NodeID && st.LastURL != "" && st.LastURL != cfg.URL {
		urlChanged = true
		prevURL = st.LastURL
	}

